INSERT INTO _sw_mileage_scholarship (snum, is_apply, semester, apply_date)
SELECT
    snum,
    #{isChecked},
    #{semester},
    NOW()
FROM _sw_student
WHERE snum = #{studentId}
  AND NOT EXISTS (
    SELECT 1
    FROM _sw_mileage_scholarship
    WHERE snum = #{studentId}
      AND semester = #{semester}
);
